from typing import Dict, Optional

class MarkovChain:
    def __init__(self, order: int = 1):
        self.order = order
        self.transitions: Dict[str, Dict[str, int]] = {}

    def train(self, text: str) -> None:
        for i in range(len(text) - self.order):
            context = text[i:i+self.order]
            next_char = text[i+self.order]
            if context not in self.transitions:
                self.transitions[context] = {}
            if next_char not in self.transitions[context]:
                self.transitions[context][next_char] = 0
            self.transitions[context][next_char] += 1

    def generate(self, length: int, seed: str | None = None, random_seed: int | None = None) -> str:
        if seed is None:
            seed = self._generate_seed(length)
        generated_text = seed
        for _ in range(length - len(seed)):
            context = generated_text[-self.order:]
            if context not in self.transitions:
                break
            next_char = max(self.transitions[context], key=self.transitions[context].get)
            generated_text += next_char
        return generated_text

    def _generate_seed(self, length: int) -> str:
        seed = chr(random.randint(97, 122))
        for _ in range(length - 1):
            seed += chr(random.randint(97, 122))
        return seed

    def to_dict(self) -> Dict[str, Dict[str, int]]:
        return self.transitions

    @classmethod
def from_dict(cls, d: Dict[str, Dict[str, int]]) -> 'MarkovChain':
    return cls(order=d['order'], transitions=d)
